STATUSES = [
    "draft",
    "active",
    "disabled",
]

STATUS_LABELS = {
    "draft": "Draft",
    "active": "Active",
    "disabled": "Disabled",
}

TERMINAL_STATUSES = {"disabled"}


def is_valid_status(value: str) -> bool:
    return value in STATUSES


def is_terminal_status(value: str) -> bool:
    return value in TERMINAL_STATUSES

ALLOWED_STATUS = {"draft", "active", "disabled"}


def validate_status(value: str) -> bool:
    return value in ALLOWED_STATUS


def normalize_status(value: str) -> str:
    return value.strip().lower()


def validate_payload(payload: dict) -> bool:
    status = normalize_status(payload["status"])
    return validate_status(status)

from backend.statuses import STATUS_LABELS


def serialize_record(record: dict) -> dict:
    status = record["status"]
    return {
        "id": record["id"],
        "status": status,
        "status_label": STATUS_LABELS[status],
    }

